    int weight = 0, value = 0;
    int n = items.length;
    int memo[][] = new int[n + 1][capacity + 1];
    for (int i = 0; i <= n ; i++)
    {
        if (i - 1 >= 0) {
            weight = items[i - 1][0];
            value = items[i - 1][1];
