public static ArrayList<String> wrap(String text, int cols) {
    ArrayList<String> lines = new ArrayList<String>();
    String line;
    while (text.length() > cols) {
        int end = text.indexOf(" ", cols); // the last index of will start at the index of cols + 1, which will look for a space after the cols. 
        // we need to get the index of the first space after cols. 
        if (end == -1) {
            end = cols;
        }
        line = text.substring(0,end);
        text = text.substring(end+1); // we need to move the substring up by 1 character, since we don't want to include the space
        lines.add(line);
    }
    lines.add(text); // we need to add the last substring, which will include the text at the end
